 {"id":"flywheel_gateway-bi2","title":"DCG+RU: Safety Integration for Agent Sweeps","description":"## Problem Statement

When RU's agent-sweep executes plans, those plans may contain dangerous commands. DCG must validate and potentially block these commands even when they originate from automated sweeps. This requires deep integration between DCG and RU.

## Background

The integration needs to handle:
1. **Pre-validation**: Before Phase 3 execution, scan all commands in approved plans
2. **Runtime blocking**: DCG hooks still fire during execution, log appropriately
3. **Approval workflow**: Pending exceptions can be created for sweep commands
4. **Audit trail**: All blocks during sweeps are linked to the sweep session
5. **Risk assessment**: DCG findings inform plan risk levels

## Implementation Plan

### 1. Plan Validation Service

```typescript
// apps/gateway/src/services/dcg-ru-integration.service.ts

import { scanContent } from "./dcg-cli.service";
import { getSweepPlan, updatePlanValidation } from "./ru-sweep.service";
import { createPendingException } from "./dcg-pending.service";
import { ingestBlockEvent } from "./dcg.service";
import { logger } from "./logger";

interface PlanValidationResult {
  valid: boolean;
  riskLevel: "low" | "medium" | "high" | "critical";
  findings: Array<{
    actionIndex: number;
    command: string;
    ruleId: string;
    severity: string;
    reason: string;
    suggestion?: string;
  }>;
  blockedCommands: number;
  warnings: number;
}

// Validate a sweep plan before execution
export async function validateSweepPlan(planId: string): Promise<PlanValidationResult> {
  const correlationId = getCorrelationId();
  const startTime = Date.now();

  logger.info({ correlationId, planId }, "Validating sweep plan against DCG");

  const plan = await getSweepPlan(planId);
  if (!plan) {
    throw new NotFoundError(`Plan not found: ${planId}`);
  }

  const parsedPlan = JSON.parse(plan.planJson);
  const actions = parsedPlan.actions || [];

  const findings: PlanValidationResult["findings"] = [];
  let blockedCommands = 0;
  let warnings = 0;

  // Scan each action's commands
  for (let i = 0; i < actions.length; i++) {
    const action = actions[i];

    // Extract commands from action
    const commands = extractCommandsFromAction(action);

    for (const command of commands) {
      const scanResult = await scanContent(command, `plan-action-${i}`);

      for (const finding of scanResult.findings) {
        findings.push({
          actionIndex: i,
          command,
          ruleId: finding.ruleId,
          severity: finding.severity,
          reason: finding.reason,
          suggestion: finding.suggestion,
        });

        if (finding.severity === "critical" || finding.severity === "high") {
          blockedCommands++;
        } else {
          warnings++;
        }
      }
    }
  }

  // Determine overall risk level
  const riskLevel = determineRiskLevel(findings);
  const valid = blockedCommands === 0;

  // Update plan with validation results
  await updatePlanValidation(planId, {
    validatedAt: new Date(),
    validationResult: valid ? "valid" : (warnings > 0 ? "warning" : "invalid"),
    validationErrors: findings.length > 0 ? JSON.stringify(findings) : null,
    riskLevel,
  });

  logger.info({
    correlationId,
    planId,
    duration_ms: Date.now() - startTime,
    valid,
    riskLevel,
    findingCount: findings.length,
    blockedCommands,
    warnings,
  }, "Plan validation completed");

  return {
    valid,
    riskLevel,
    findings,
    blockedCommands,
    warnings,
  };
}

// Validate all plans in a sweep session
export async function validateSweepSession(sessionId: string): Promise<{
  totalPlans: number;
  validPlans: number;
  invalidPlans: number;
  planResults: Record<string, PlanValidationResult>;
}> {
  const correlationId = getCorrelationId();
  const plans = await getSweepPlans(sessionId);

  const planResults: Record<string, PlanValidationResult> = {};
  let validPlans = 0;
  let invalidPlans = 0;

  for (const plan of plans) {
    const result = await validateSweepPlan(plan.id);
    planResults[plan.id] = result;

    if (result.valid) {
      validPlans++;
    } else {
      invalidPlans++;
    }
  }

  logger.info({
    correlationId,
    sessionId,
    totalPlans: plans.length,
    validPlans,
    invalidPlans,
  }, "Session validation completed");

  return {
    totalPlans: plans.length,
    validPlans,
    invalidPlans,
    planResults,
  };
}

// Create pending exceptions for blocked commands in a plan
export async function createExceptionsForPlan(
  planId: string,
  approvedBy: string
): Promise<string[]> {
  const plan = await getSweepPlan(planId);
  if (!plan || !plan.validationErrors) {
    return [];
  }

  const findings = JSON.parse(plan.validationErrors);
  const exceptionCodes: string[] = [];

  for (const finding of findings) {
    if (finding.severity === "critical" || finding.severity === "high") {
      const exception = await createPendingException({
        command: finding.command,
        pack: finding.ruleId.split(":")[0],
        ruleId: finding.ruleId,
        reason: `Sweep plan command: ${finding.reason}`,
        severity: finding.severity,
        agentId: `sweep:${plan.sessionId}`,
        ttlSeconds: 3600, // 1 hour for sweep commands
      });

      exceptionCodes.push(exception.shortCode);
    }
  }

  logger.info({
    planId,
    exceptionCount: exceptionCodes.length,
    approvedBy,
  }, "Created pending exceptions for plan");

  return exceptionCodes;
}

// Helper: Extract commands from an action
function extractCommandsFromAction(action: any): string[] {
  const commands: string[] = [];

  if (action.type === "commit") {
    // Git commands for commits
    if (action.files) {
      commands.push(`git add ${action.files.join(" ")}`);
    }
    commands.push(`git commit -m "${action.message}"`);
    if (action.push) {
      commands.push(`git push`);
    }
  } else if (action.type === "release") {
    // Release commands
    commands.push(`git tag ${action.version}`);
    if (action.push) {
      commands.push(`git push --tags`);
    }
  } else if (action.type === "shell") {
    // Direct shell commands
    commands.push(action.command);
  } else if (action.type === "script") {
    // Script content
    commands.push(action.content);
  }

  return commands;
}

// Helper: Determine risk level from findings
function determineRiskLevel(
  findings: PlanValidationResult["findings"]
): "low" | "medium" | "high" | "critical" {
  const hasCritical = findings.some(f => f.severity === "critical");
  const hasHigh = findings.some(f => f.severity === "high");
  const hasMedium = findings.some(f => f.severity === "medium");

  if (hasCritical) return "critical";
  if (hasHigh) return "high";
  if (hasMedium) return "medium";
  return "low";
}
```

### 2. Execution Integration

```typescript
// apps/gateway/src/services/ru-sweep-executor.ts

import { validateSweepPlan, createExceptionsForPlan } from "./dcg-ru-integration.service";
import { ingestBlockEvent } from "./dcg.service";
import { validateExceptionForExecution, markExceptionExecuted } from "./dcg-pending.service";
import { logger } from "./logger";

interface ExecutionResult {
  success: boolean;
  blockedByDCG: boolean;
  blockDetails?: {
    ruleId: string;
    reason: string;
    shortCode?: string;
  };
  output?: string;
  error?: string;
}

// Execute a single action with DCG integration
export async function executeActionWithDCG(
  sessionId: string,
  planId: string,
  actionIndex: number,
  action: any
): Promise<ExecutionResult> {
  const correlationId = getCorrelationId();
  const startTime = Date.now();

  logger.info({
    correlationId,
    sessionId,
    planId,
    actionIndex,
    actionType: action.type,
  }, "Executing action with DCG checks");

  const commands = extractCommandsFromAction(action);

  for (const command of commands) {
    // Check for approved pending exception
    const commandHash = hashCommand(command);
    const exception = await validateExceptionForExecution(commandHash);

    if (!exception) {
      // Test if command would be blocked
      const testResult = await testCommand(command);

      if (testResult.blocked) {
        // Log the block event linked to sweep
        await ingestBlockEvent({
          command,
          pack: testResult.matchedRule!.pack,
          ruleId: testResult.matchedRule!.ruleId,
          severity: testResult.matchedRule!.severity,
          reason: testResult.matchedRule!.reason,
          agentId: `sweep:${sessionId}`,
          contextClassification: "executed",
        });

        logger.warn({
          correlationId,
          sessionId,
          planId,
          actionIndex,
          command: command.substring(0, 50),
          ruleId: testResult.matchedRule!.ruleId,
        }, "Sweep action blocked by DCG");

        return {
          success: false,
          blockedByDCG: true,
          blockDetails: {
            ruleId: testResult.matchedRule!.ruleId,
            reason: testResult.matchedRule!.reason,
          },
        };
      }
    }

    // Execute the command
    try {
      const result = await executeCommand(command, {
        cwd: getRepoCwd(action),
        timeout: 60000,
      });

      // If we had an exception, mark it as executed
      if (exception) {
        await markExceptionExecuted(exception.id, "success");
      }

      if (result.exitCode !== 0) {
        return {
          success: false,
          blockedByDCG: false,
          error: result.stderr,
        };
      }
    } catch (error) {
      if (exception) {
        await markExceptionExecuted(exception.id, "failed");
      }

      logger.error({
        correlationId,
        sessionId,
        planId,
        actionIndex,
        error,
      }, "Action execution failed");

      return {
        success: false,
        blockedByDCG: false,
        error: error.message,
      };
    }
  }

  logger.info({
    correlationId,
    sessionId,
    planId,
    actionIndex,
    duration_ms: Date.now() - startTime,
  }, "Action executed successfully");

  return {
    success: true,
    blockedByDCG: false,
  };
}

// Execute all actions in a plan with DCG checks
export async function executePlanWithDCG(
  sessionId: string,
  planId: string
): Promise<{
  success: boolean;
  actionsExecuted: number;
  actionsBlocked: number;
  actionsFailed: number;
  results: ExecutionResult[];
}> {
  const plan = await getSweepPlan(planId);
  const parsedPlan = JSON.parse(plan.planJson);
  const actions = parsedPlan.actions || [];

  const results: ExecutionResult[] = [];
  let actionsExecuted = 0;
  let actionsBlocked = 0;
  let actionsFailed = 0;

  for (let i = 0; i < actions.length; i++) {
    const result = await executeActionWithDCG(sessionId, planId, i, actions[i]);
    results.push(result);

    if (result.success) {
      actionsExecuted++;
    } else if (result.blockedByDCG) {
      actionsBlocked++;
      // Stop execution on DCG block
      break;
    } else {
      actionsFailed++;
      // Stop execution on failure
      break;
    }
  }

  return {
    success: actionsBlocked === 0 && actionsFailed === 0,
    actionsExecuted,
    actionsBlocked,
    actionsFailed,
    results,
  };
}
